INSERT INTO MCP_UPLOAD_PHONE_INFO
(
    UPLOAD_PHONE_SRL_NO
    ,REQ_MODEL_NAME
    ,MODEL_ID
    ,REQ_PHONE_SN
    ,EID
    ,IMEI1
    ,IMEI2
    ,UPLOAD_PHONE_IMG
    ,ACCESS_IP
    ,USER_ID
    ,SYS_DT
    ,SYS_RDATE
    ,RST_CD
    ,EVNT_CD
    ,RSLT_CD
    ,RSLT_YN
    ,RSLT_MSG
    , PRNTS_CONTRACT_NO
)
VALUES
(
    SQ_UPLOAD_PHONE_SEQ.NEXTVAL
    ,#{reqModelName}
    ,#{modelId}
    ,#{reqPhoneSn}
    ,#{eid}
    ,#{imei1}
    ,#{imei2}
    ,#{uploadPhoneImg}
    ,#{accessIp}
    ,#{userId}
    ,TO_CHAR(SYSDATE, 'YYYYMMDD')
    ,SYSDATE
    ,'R'
    ,#{evntCd}
    ,#{rsltCd}
    ,#{rsltYn}
    ,#{rsltMsg}
    ,#{prntsContractNo}
)

        SELECT SQ_UPLOAD_PHONE_SEQ.CURRVAL FROM DUAL

mapper.update:
UPDATE /*EsimMapper.updateMcpUploadPhoneInfoDto   */
    MCP_UPLOAD_PHONE_INFO
SET
    REQ_MODEL_NAME = #{reqModelName}
    ,MODEL_ID = #{modelId}
    ,REQ_PHONE_SN = #{reqPhoneSn}
    ,MOVE_TLCM_IND_CD = #{moveTlcmIndCd}
    ,MOVE_CMNC_GNRT_IND_CD = #{moveCmncGnrtIndCd}
    ,RST_CD = #{rstCd}
WHERE
    UPLOAD_PHONE_SRL_NO = #{uploadPhoneSrlNo}

UPDATE /*EsimMapper.updateServiceRst   */
    MCP_UPLOAD_PHONE_INFO
SET
    EVNT_CD  = #{evntCd}
    , RSLT_CD  = #{rsltCd}
    , RSLT_YN  = #{rsltYn}
    , RSLT_MSG  = #{rsltMsg}
WHERE
    UPLOAD_PHONE_SRL_NO = #{uploadPhoneSrlNo}

